import { useSimulationStore } from '../store';

export default function MainArea() {
  const { currentPrice, isRunning } = useSimulationStore();

  return (
    <main className="flex-1 flex flex-col items-center justify-center p-6">
      <div className="w-full h-full bg-[#161b22]/80 backdrop-blur-md border border-white/10 rounded-xl flex flex-col items-center justify-center gap-4 min-h-[400px]">
        <div className="text-center">
          <p className="text-xs text-white/30 uppercase tracking-widest mb-1">Current Price</p>
          <p className="font-mono text-4xl font-bold text-white">
            ${currentPrice.toFixed(2)}
          </p>
        </div>

        <div className={`flex items-center gap-2 text-sm font-mono ${isRunning ? 'text-[#00ff88]' : 'text-white/30'}`}>
          <span className={`w-2 h-2 rounded-full ${isRunning ? 'bg-[#00ff88] animate-pulse' : 'bg-white/20'}`} />
          {isRunning ? 'SIMULATION RUNNING' : 'SIMULATION IDLE'}
        </div>

        <p className="text-white/20 text-sm mt-6 tracking-widest uppercase">
          Canvas Simulation Engine Mount
        </p>
      </div>
    </main>
  );
}
